1	/** Coordinates of a live cell as [x, y]. */
2	export type Cell = [number, number];
3	
4	const key = ([x, y]: Cell): string => `${x},${y}`;
5	
6	const NEIGHBOR_OFFSETS: Cell[] = [
7	  [-1, -1], [0, -1], [1, -1],
8	  [-1,  0],          [1,  0],
9	  [-1,  1], [0,  1], [1,  1],
10	];
11	
12	const neighborsOf = ([x, y]: Cell): Cell[] =>
13	  NEIGHBOR_OFFSETS.map(([dx, dy]) => [x + dx, y + dy]);
14	
15	const countLiveNeighbors = (cell: Cell, liveSet: Set<string>): number =>
16	  neighborsOf(cell).filter((n) => liveSet.has(key(n))).length;
17	
18	const isAliveNextGeneration = (liveNeighbors: number, isCurrentlyAlive: boolean): boolean =>
19	  liveNeighbors === 3 || (liveNeighbors === 2 && isCurrentlyAlive);
20	
21	export function nextGeneration(liveCells: Cell[]): Cell[] {
22	  const liveSet = new Set(liveCells.map(key));
23	  const candidates = new Map<string, Cell>();
24	  for (const live of liveCells) {
25	    for (const cell of [live, ...neighborsOf(live)]) candidates.set(key(cell), cell);
26	  }
27	  return [...candidates].filter(([k, cell]) =>
28	    isAliveNextGeneration(countLiveNeighbors(cell, liveSet), liveSet.has(k)),
29	  ).map(([, cell]) => cell);
30	}
