14	  it("block still life remains unchanged — [(0,0),(1,0),(0,1),(1,1)] → same 4 cells", () => {
15	    const block: Cell[] = [[0, 0], [1, 0], [0, 1], [1, 1]];
16	    const result = nextGeneration(block);
17	    expect(result).toHaveLength(4);
18	    expect(result).toEqual(expect.arrayContaining(block));
19	  });
20	  it("live cell with > 3 neighbors dies (overpopulation) — center of full 3x3 dies", () => {
